const msgData   = $('Extrair Mensagem').first().json
const sessionRow = $('Buscar Sessão').first()?.json
const clientRow  = $('Buscar Cliente').first()?.json

const phone        = msgData.phone
const incoming     = msgData.incomingText
const rawText      = msgData.rawText
const phoneNumberId = msgData.phoneNumberId
const _apiBaseUrl = $env.API_BASE_URL
const _apiToken   = $env.API_INTERNAL_TOKEN

const currentState = sessionRow?.current_state ?? 'new'
const ctx          = typeof sessionRow?.context === 'string'
  ? JSON.parse(sessionRow.context)
  : (sessionRow?.context ?? {})

// ── Helpers ──────────────────────────────────────────────────
// ── Interactive message builders ──────────────────────────────────────────────
function makeList(bodyText, rows, opts) {
  opts = opts || {}
  return {
    type: 'list',
    body: { text: bodyText },
    footer: { text: opts.footer || 'Selecione uma opção' },
    action: {
      button: opts.button || 'Ver opções',
      sections: [{ title: opts.section || 'Opções', rows: rows }],
    },
  }
}
function makeButtons(bodyText, buttons, footer) {
  const obj = {
    type: 'button',
    body: { text: bodyText },
    action: { buttons: buttons.map(function(b) { return { type: 'reply', reply: { id: b[0], title: b[1] } } }) },
  }
  if (footer) obj.footer = { text: footer }
  return obj
}

// ── FIPE Lookup ─────────────────────────────────────────────────
async function lookupFipe(brand, model, year, fuel, vehicleType) {
  if (typeof fetch === 'undefined') return null
  const params = new URLSearchParams({ brand, model, year, fuel, vehicleType })
  try {
    const resp = await fetch(`${_apiBaseUrl}/api/fipe/price?${params}`, {
      headers: { Authorization: `Bearer ${_apiToken}` },
    })
    if (!resp.ok) return null
    const body = await resp.json()
    return body.found ? body.data : null
  } catch (e) {
    return null
  }
}
