    result = { response: '😊 Tudo bem! Qualquer dúvida é só enviar "oi".', newState: 'completed', ctx }
  }
}

// ── Fallback ──────────────────────────────────────────────────
if (!result) {
  result = {
    response: 'Desculpe, não entendi. Envie "oi" para recomeçar ou "cancelar" para sair.',
    newState: currentState, ctx,
  }
}



// Inject API config for downstream HTTP Request nodes
const _result = result ?? { response: msgData.response, newState: currentState, ctx }
const finalOutput = {
  phone,
  phoneNumberId,
  ..._result,
  newContext: _result.ctx ?? _result.newContext ?? ctx,
  _apiBaseUrl,
  _apiToken,
}
return [{ json: finalOutput }]

